// -- RESUME OPEN ---------------------------------------------------------------
var RESUME_PDF = "data:application/pdf;base64,";
function openResume(){
  // Method 1: Blob URL (best - opens inline in browser)
  try {
    var parts = RESUME_PDF.split(',');
    var byteChars = atob(parts[1]);
    var byteArr = [];
    for(var i=0;i<byteChars.length;i++) byteArr.push(byteChars.charCodeAt(i));
    var blob = new Blob([new Uint8Array(byteArr)], {type:'application/pdf'});
    var blobUrl = URL.createObjectURL(blob);
    var tab = window.open(blobUrl, '_blank');
    if(!tab){
      // Popup blocked - fallback to download
      var a = document.createElement('a');
      a.href = blobUrl;
      a.download = 'Arulvelan_Ayyappan_Resume.pdf';
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
    }
    return;
  } catch(e) {
    console.warn('Blob method failed:', e);
  }
  // Method 2: direct base64 download
  try {
    var a = document.createElement('a');
    a.href = RESUME_PDF;
    a.download = 'Arulvelan_Ayyappan_Resume.pdf';
    a.target = '_blank';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  } catch(e2) {
    console.warn('Download failed:', e2);
  }
}
// -- LOADER -- completely isolated, never blocks -----------------------------
(function(){
  var lbar    = document.getElementById('lbar');
  var loader  = document.getElementById('loader');
  var hidden  = false;

  function hideLoader(){
    if(hidden) return;
    hidden = true;
    if(lbar)   lbar.style.width = '100%';
    if(loader){
      loader.style.transition = 'opacity 0.35s ease';
      loader.style.opacity    = '0';
    }
    setTimeout(function(){
      if(loader) loader.style.display = 'none';
      try{ startApp(); }catch(e){ console.error('startApp error:',e); }
    }, 370);
  }

  // Progress bar animation
  var p  = 0;
  var iv = setInterval(function(){
    p += Math.random() * 25 + 8;
    if(p > 95) p = 95;          // stop just before 100 until done
    if(lbar) lbar.style.width = p + '%';
  }, 60);

  // Hard kill after 1.8s -- NOTHING can keep loader alive longer
  setTimeout(function(){
    clearInterval(iv);
    hideLoader();
  }, 1800);

  // Also kill as soon as DOM is ready
  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', function(){
      clearInterval(iv);
      setTimeout(hideLoader, 200);
    });
  } else {
    clearInterval(iv);
    setTimeout(hideLoader, 100);
  }
})();

