// -- HERO ANIMATIONS --------------------------------------------------------
function animateHero(){
  var items = [
    {sel:'.hero-eyebrow',  d:0.1},
    {sel:'.hero-name',     d:0.22},
    {sel:'.hero-typerow',  d:0.36},
    {sel:'.hero-meta',     d:0.48},
    {sel:'.hero-btns',     d:0.60},
    {sel:'.hero-socials',  d:0.72},
    {sel:'.scroll-hint',   d:0.90},
  ];
  items.forEach(function(it){
    var el = document.querySelector(it.sel);
    if(!el) return;
    if(typeof gsap !== 'undefined'){
      gsap.to(el,{opacity:1,y:0,duration:0.65,delay:it.d,ease:'power3.out'});
    } else {
      setTimeout(function(){ el.style.opacity='1'; el.style.transform='translateY(0)'; el.style.transition='opacity 0.6s,transform 0.6s'; }, it.d*1000);
    }
  });
}

// -- TYPEWRITER -------------------------------------------------------------
function initTypewriter(){
  var words = ['ECE Engineer','AI Agent Builder','IoT Developer','Problem Solver','Full-Stack Dev'];
  var wi=0, ci=0, del=false;
  var el = document.getElementById('tw-text');
  if(!el) return;
  function tick(){
    var w = words[wi];
    if(!del){ el.textContent = w.slice(0,++ci); if(ci===w.length){del=true;setTimeout(tick,1400);return;} }
    else { el.textContent = w.slice(0,--ci); if(ci===0){del=false;wi=(wi+1)%words.length;} }
    setTimeout(tick, del?55:90);
  }
  setTimeout(tick, 800);
}

// -- THREE.JS PARTICLES -----------------------------------------------------
function initThreeJS(){
  try{
    var canvas = document.getElementById('hero-canvas');
    if(!canvas || typeof THREE === 'undefined') return;
    var renderer = new THREE.WebGLRenderer({canvas:canvas,alpha:true});
    renderer.setPixelRatio(Math.min(window.devicePixelRatio,2));
    renderer.setSize(window.innerWidth,window.innerHeight);
    var scene = new THREE.Scene();
    var camera = new THREE.PerspectiveCamera(60,window.innerWidth/window.innerHeight,0.1,100);
    camera.position.z=5;
    var N=500, pos=new Float32Array(N*3), col=new Float32Array(N*3), vel=new Float32Array(N*3);
    var c1=new THREE.Color('#FF6B2B'), c2=new THREE.Color('#FFAA4C');
    for(var i=0;i<N;i++){
      pos[i*3]=(Math.random()-.5)*14; pos[i*3+1]=(Math.random()-.5)*8-4; pos[i*3+2]=(Math.random()-.5)*3;
      vel[i*3]=(Math.random()-.5)*.004; vel[i*3+1]=Math.random()*.008+.002; vel[i*3+2]=0;
      var t=Math.random(), c=c1.clone().lerp(c2,t);
      col[i*3]=c.r; col[i*3+1]=c.g; col[i*3+2]=c.b;
    }
    var geo=new THREE.BufferGeometry();
    geo.setAttribute('position',new THREE.BufferAttribute(pos,3));
    geo.setAttribute('color',new THREE.BufferAttribute(col,3));
    var mat=new THREE.PointsMaterial({size:.04,vertexColors:true,transparent:true,opacity:.7,blending:THREE.AdditiveBlending,depthWrite:false,sizeAttenuation:true});
    scene.add(new THREE.Points(geo,mat));
    var mx=0,my=0;
    document.addEventListener('mousemove',function(e){mx=(e.clientX/window.innerWidth-.5)*.4;my=-(e.clientY/window.innerHeight-.5)*.25;});
    window.addEventListener('resize',function(){renderer.setSize(window.innerWidth,window.innerHeight);camera.aspect=window.innerWidth/window.innerHeight;camera.updateProjectionMatrix();});
    (function anim(){
      requestAnimationFrame(anim);
      var p=geo.attributes.position.array;
      for(var i=0;i<N;i++){p[i*3]+=vel[i*3];p[i*3+1]+=vel[i*3+1];if(p[i*3+1]>5){p[i*3+1]=-4;p[i*3]=(Math.random()-.5)*14;}}
      geo.attributes.position.needsUpdate=true;
      camera.position.x+=(mx-camera.position.x)*.03;
      camera.position.y+=(my-camera.position.y)*.03;
      renderer.render(scene,camera);
    })();
  }catch(e){ console.warn('Three.js skipped:',e.message); }
}

// -- SCROLL REVEAL ----------------------------------------------------------
function initScrollReveal(){
  if(typeof gsap === 'undefined' || typeof ScrollTrigger === 'undefined') return;
  gsap.registerPlugin(ScrollTrigger);
  gsap.utils.toArray('.reveal').forEach(function(el){
    gsap.fromTo(el,{opacity:0,y:40},{opacity:1,y:0,duration:0.75,ease:'power3.out',
      scrollTrigger:{trigger:el,start:'top 88%',toggleActions:'play none none none'}});
  });
}

// -- PROJECT FILTER ---------------------------------------------------------
function initProjectFilter(){
  document.querySelectorAll('.ptab').forEach(function(tab){
    tab.addEventListener('click',function(){
      document.querySelectorAll('.ptab').forEach(function(t){t.classList.remove('active');});
      tab.classList.add('active');
      var f=tab.getAttribute('data-f');
      document.querySelectorAll('.pcard').forEach(function(c){
        c.style.display=(f==='all'||c.getAttribute('data-cat')===f)?'flex':'none';
      });
    });
  });
}

// -- NAV HIGHLIGHT ----------------------------------------------------------
function initNavHighlight(){
  var secs=document.querySelectorAll('section[id]');
  var links=document.querySelectorAll('.nav-links a');
  window.addEventListener('scroll',function(){
    var cur='';
    secs.forEach(function(s){if(window.scrollY>=s.offsetTop-130)cur=s.id;});
    links.forEach(function(a){a.style.color=a.getAttribute('href')==='#'+cur?'var(--orange)':'';});
  });
}

// -- LEETCODE -- multi-strategy live fetch ------------------------------------
function initLeetCode(){
  var u = 'arulvelanayyappan';

  // Show loading
  var totalEl = document.getElementById('lc-total');
  if(totalEl) totalEl.textContent = '...';

  // Strategy 1: alfa-leetcode-api (direct, works if CORS open)
  function tryAlfa(){
    return Promise.all([
      fetch('https://alfa-leetcode-api.onrender.com/' + u, {mode:'cors'}),
      fetch('https://alfa-leetcode-api.onrender.com/' + u + '/submission?limit=5', {mode:'cors'})
    ]).then(function(rs){
      if(!rs[0].ok) throw new Error('alfa profile fail');
      return Promise.all([rs[0].json(), rs[1].ok ? rs[1].json() : Promise.resolve({})]);
    }).then(function(data){
      var p = data[0], s = data[1];
      if(!p.totalSolved && !p.easySolved) throw new Error('no data');
      return {
        easy:  p.easySolved   || 0,
        med:   p.mediumSolved || 0,
        hard:  p.hardSolved   || 0,
        total: p.totalSolved  || 0,
        rank:  p.ranking      || 0,
        recent: (s.submission||[]).slice(0,5).map(function(x){
          return {title:x.title||x.titleSlug||'Unknown', lang:x.lang||'java', timestamp:x.timestamp||0, status:x.statusDisplay||'Accepted'};
        })
      };
    });
  }

  // Strategy 2: LeetCode GraphQL via corsproxy.io
  function tryGraphQL(){
    var q = JSON.stringify({
      query: 'query($u:String!){matchedUser(username:$u){profile{ranking}submitStats{acSubmissionNum{difficulty count}}}recentAcSubmissionList(username:$u,limit:5){title timestamp lang}}',
      variables: {u: u}
    });
    return fetch('https://corsproxy.io/?' + encodeURIComponent('https://leetcode.com/graphql'), {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body: q
    }).then(function(r){ if(!r.ok) throw new Error('graphql fail'); return r.json(); })
    .then(function(d){
      if(!d.data || !d.data.matchedUser) throw new Error('no user');
      var m = d.data.matchedUser;
      var stats = m.submitStats.acSubmissionNum;
      var easy  = (stats.find(function(s){return s.difficulty==='Easy';})||{}).count||0;
      var med   = (stats.find(function(s){return s.difficulty==='Medium';})||{}).count||0;
      var hard  = (stats.find(function(s){return s.difficulty==='Hard';})||{}).count||0;
      var recent = (d.data.recentAcSubmissionList||[]).map(function(x){
        return {title:x.title, lang:x.lang||'java', timestamp:x.timestamp||0, status:'Accepted'};
      });
      return {easy:easy, med:med, hard:hard, total:easy+med+hard, rank:m.profile.ranking||0, recent:recent};
    });
  }

  // Strategy 3: leetcode-stats-api via allorigins proxy
  function tryStatsAPI(){
    var url = 'https://leetcode-stats-api.herokuapp.com/' + u;
    return fetch('https://api.allorigins.win/get?url=' + encodeURIComponent(url))
      .then(function(r){ return r.json(); })
      .then(function(d){
        var p = JSON.parse(d.contents);
        if(!p.totalSolved) throw new Error('no data');
        return {easy:p.easySolved||0, med:p.mediumSolved||0, hard:p.hardSolved||0,
                total:p.totalSolved||0, rank:p.ranking||0, recent:[]};
      });
  }

  // Strategy 4: alfa via allorigins proxy
  function tryAlfaProxy(){
    var url = 'https://alfa-leetcode-api.onrender.com/' + u;
    return fetch('https://api.allorigins.win/get?url=' + encodeURIComponent(url))
      .then(function(r){ return r.json(); })
      .then(function(d){
        var p = JSON.parse(d.contents);
        if(!p.totalSolved && !p.easySolved) throw new Error('no data');
        return {easy:p.easySolved||0, med:p.mediumSolved||0, hard:p.hardSolved||0,
                total:p.totalSolved||0, rank:p.ranking||0, recent:[]};
      });
  }

  // Run strategies in sequence
  tryAlfa()
    .catch(function(){ return tryGraphQL(); })
    .catch(function(){ return tryStatsAPI(); })
    .catch(function(){ return tryAlfaProxy(); })
    .then(function(data){
      renderLC(data);
      // Green dot = live
      var dot = document.querySelector('#leetcode .dot');
      if(dot){ dot.style.background='#2db55d'; dot.style.animation='pulse 2s ease infinite'; }
      // Show "Live" label
      var liveLabel = document.getElementById('lc-live-label');
      if(liveLabel) liveLabel.textContent = '* Live Data';
    })
    .catch(function(err){
      console.warn('All LeetCode strategies failed:', err);
      var dot = document.querySelector('#leetcode .dot');
      if(dot) dot.style.background = '#f59e0b';
      var liveLabel = document.getElementById('lc-live-label');
      if(liveLabel){ liveLabel.textContent = '* Snapshot'; liveLabel.style.color='#f59e0b'; }
      renderLC({
        easy:243, med:375, hard:104, total:722, rank:83197,
        recent:[
          {title:'Linked List Cycle II', lang:'java', timestamp:1743033600, status:'Accepted'},
          {title:'N-Queens II',          lang:'java', timestamp:1742860800, status:'Accepted'},
          {title:'Course Schedule II',   lang:'java', timestamp:1742774400, status:'Accepted'},
          {title:'Swap Nodes in Pairs',  lang:'java', timestamp:1742774400, status:'Accepted'},
          {title:'Combinations',         lang:'java', timestamp:1742688000, status:'Accepted'}
        ]
      });
    });
}

function renderLC(o){
  var totalEl = document.getElementById('lc-total');
  var rankEl  = document.getElementById('lc-rank');
  var stotEl  = document.getElementById('lc-stot');
  if(totalEl) totalEl.textContent = o.total;
  if(rankEl)  rankEl.textContent  = '#' + Number(o.rank).toLocaleString();
  if(stotEl)  stotEl.textContent  = o.total + '+';

  var evEl = document.getElementById('lc-ev');
  var mvEl = document.getElementById('lc-mv');
  var hvEl = document.getElementById('lc-hv');
  if(evEl) evEl.textContent = o.easy  + ' / 951';
  if(mvEl) mvEl.textContent = o.med   + ' / 2074';
  if(hvEl) hvEl.textContent = o.hard  + ' / 948';

  setTimeout(function(){
    var arc = document.getElementById('lc-arc');
    if(arc){
      arc.style.transition = 'stroke-dashoffset 1.4s cubic-bezier(.16,1,.3,1)';
      arc.style.strokeDashoffset = String(226.2 - (Math.min(o.total/3973,1)*226.2));
    }
    var eb=document.getElementById('lc-eb'), mb=document.getElementById('lc-mb'), hb=document.getElementById('lc-hb');
    if(eb) eb.style.width=(o.easy/951*100)+'%';
    if(mb) mb.style.width=(o.med/2074*100)+'%';
    if(hb) hb.style.width=(o.hard/948*100)+'%';
  }, 300);

  var actsEl = document.getElementById('lc-acts');
  if(!actsEl) return;
  if(!o.recent || o.recent.length===0){
    actsEl.innerHTML='<div style="font-size:.75rem;color:#666;font-family:Inter,sans-serif;">Stats loaded v</div>';
    return;
  }
  actsEl.innerHTML = o.recent.map(function(s){
    var d  = new Date(parseInt(s.timestamp)*1000);
    var ds = String(d.getFullYear()).slice(2)+'.'+String(d.getMonth()+1).padStart(2,'0')+'.'+String(d.getDate()).padStart(2,'0');
    var lang = (s.lang||'java').replace('java','Python').replace('python3','Python').replace('cpp','C++').replace('javascript','JS');
    var ok = !(s.status||'').toLowerCase().includes('wrong');
    return '<div style="display:flex;align-items:center;gap:.65rem;font-size:.78rem;">'+
      '<span style="font-family:Inter,sans-serif;font-size:.67rem;color:#666;min-width:50px;">'+ds+'</span>'+
      '<span style="background:'+(ok?'#2db55d':'#ef4444')+';color:#fff;font-size:.58rem;font-weight:700;padding:.12rem .38rem;border-radius:3px;font-family:Inter,sans-serif;">'+(ok?'AC':'WA')+'</span>'+
      '<span style="font-family:Inter,sans-serif;font-size:.68rem;color:#FF6B2B;font-weight:600;">'+lang+'</span>'+
      '<span style="color:#bbb;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">'+s.title+'</span>'+
      '</div>';
  }).join('');
}

// -- MUSIC TOGGLE -----------------------------------------------------------
var musicPlaying = false;
function toggleMusic(){
  var audio = document.getElementById('bg-music');
  var ring  = document.getElementById('music-ring');
  var pill  = document.getElementById('now-playing');
  var btn   = document.getElementById('av-btn');

  if(!musicPlaying){
    audio.play().then(function(){
      musicPlaying = true;
      ring.style.display = 'block';
      pill.style.display = 'flex';
      btn.style.animation = 'avPulse 2s ease infinite';
    }).catch(function(e){ console.warn('Audio play blocked:', e); });
  } else {
    audio.pause();
    musicPlaying = false;
    ring.style.display = 'none';
    pill.style.display = 'none';
    btn.style.animation = '';
  }
}

