// -- CONTACT FORM SUBMIT -- sends directly to arulvelan24@gmail.com ----------
function submitForm(btn){
  var nameEl   = document.getElementById('cf-name');
  var emailEl  = document.getElementById('cf-email');
  var msgEl    = document.getElementById('cf-msg');
  var statusEl = document.getElementById('cf-status');

  var name  = nameEl  ? nameEl.value.trim()  : '';
  var email = emailEl ? emailEl.value.trim() : '';
  var msg   = msgEl   ? msgEl.value.trim()   : '';

  function showStatus(text, color, icon){
    if(!statusEl) return;
    statusEl.innerHTML = '<span style="font-size:1.1rem">' + (icon||'') + '</span> ' + text;
    statusEl.style.color   = color;
    statusEl.style.display = 'block';
    statusEl.style.marginTop = '1rem';
    statusEl.style.fontFamily = 'Inter,sans-serif';
    statusEl.style.fontSize = '.85rem';
  }

  // Validate
  if(!name)                        { showStatus('Please enter your name.', '#f59e0b', '!'); return; }
  if(!email || !email.includes('@')){ showStatus('Please enter a valid email.', '#f59e0b', '!'); return; }
  if(!msg)                         { showStatus('Please write a message.', '#f59e0b', '!'); return; }

  btn.disabled = true;
  btn.innerHTML = 'Sending...';
  if(statusEl) statusEl.style.display = 'none';

  // If key not configured yet, show clear instructions
  if(!W3F_KEY || W3F_KEY === 'YOUR_WEB3FORMS_KEY'){
    btn.disabled = false;
    btn.innerHTML = 'Send Message';
    showStatus('Form key not set. See setup instructions below.', '#f59e0b', '!');
    var inst = document.getElementById('w3f-instructions');
    if(inst) inst.style.display = 'block';
    return;
  }

  // Send via Web3Forms API - no page redirect, message goes straight to Gmail
  fetch('https://api.web3forms.com/submit', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
    body: JSON.stringify({
      access_key:  W3F_KEY,
      name:        name,
      email:       email,
      message:     msg,
      subject:     'Portfolio Contact from ' + name,
      from_name:   name,
      replyto:     email,
      botcheck:    ''
    })
  })
  .then(function(r){ return r.json(); })
  .then(function(data){
    if(data.success){
      btn.innerHTML = 'Sent!';
      btn.style.background = '#22c55e';
      showStatus('Message delivered to arulvelan24@gmail.com!', '#22c55e', 'v');
      if(nameEl)  nameEl.value  = '';
      if(emailEl) emailEl.value = '';
      if(msgEl)   msgEl.value   = '';
      setTimeout(function(){
        btn.innerHTML = 'Send Message';
        btn.style.background = '';
        btn.disabled = false;
        if(statusEl) statusEl.style.display = 'none';
      }, 4000);
    } else {
      throw new Error(data.message || 'Failed');
    }
  })
  .catch(function(err){
    console.error('Web3Forms:', err);
    btn.disabled = false;
    btn.innerHTML = 'Send Message';
    showStatus('Could not send. Please email arulvelan24@gmail.com directly.', '#ef4444', 'x');
  });
}